questions.reference_solution:
function compressStrategy(info, maxSize) {
  if (info.size <= maxSize || info.width <= 0) return info;
  const ratio = Math.sqrt(maxSize / info.size);
  return {
    width: Math.floor(info.width * ratio),
    height: Math.floor(info.height * ratio),
    size: Math.floor(info.size * ratio * ratio)
  };
}

