  // 请在此处实现
  return (() => {}) as any;
}

questions.reference_solution:
let timer: any = null;
const throttled = function(this: any, ...args: any[]) {
  if (timer) return;
  fn.apply(this, args);
  timer = setTimeout(() => timer = null, delay);
};
throttled.cancel = () => clearTimeout(timer);
return throttled;

