interface Item { id: string; data: any; }
interface DiffResult { added: Item[]; removed: Item[]; updated: Item[]; }

function diffList(oldList: Item[], newList: Item[]): DiffResult {
  // 请在此处实现
  return { added: [], removed: [], updated: [] };
}

questions.reference_solution:
const oldMap = new Map(oldList.map(i => [i.id, i]));
const result = { added: [], removed: [], updated: [] };
newList.forEach(item => {
  const old = oldMap.get(item.id);
  if (!old) result.added.push(item);
  else if (JSON.stringify(old) !== JSON.stringify(item)) result.updated.push(item);
  oldMap.delete(item.id);
});
result.removed = Array.from(oldMap.values());
return result;

